mapper.select:
SELECT VA.Volun_Act_No, VA.Volun_Act_Title, VA.Volun_Act_Recru_Begin, VA.Volun_Act_Recru_End, VA.Volun_Act_Proc_Begin, VA.Volun_Act_Proc_End, VA.Volun_Act_Point, VA.Volun_Act_Address,
/* 활동분야 이름 변환 */ CASE VA.Volun_Act_Act_Type WHEN 1 THEN '환경' WHEN 2 THEN '의료' WHEN 3 THEN '교육' WHEN 4 THEN '생활·편의' WHEN 5 THEN '문화·체육·예술' ELSE '기타' END AS actTypeName,
/* 연령 변환 */ CASE VA.Volun_Act_Age_Group WHEN 1 THEN '청소년(14~19)' WHEN 2 THEN '청년(20~30)' WHEN 3 THEN '직장인(30+)' END AS ageGroupName,
/* 모집 상태 */
CASE WHEN SYSDATE < VA.Volun_Act_Recru_Begin THEN '모집예정' WHEN SYSDATE BETWEEN VA.Volun_Act_Recru_Begin AND VA.Volun_Act_Recru_End THEN '모집중' ELSE '모집마감' END AS recruitStatusName
FROM TBL_VOLUN_ACTIVITY VA LEFT JOIN TBL_ORGAN O ON VA.ORGAN_NO = O.ORGAN_NO
AND VA.Volun_Act_Act_Type = #{volunActActType}
AND VA.Volun_Act_Age_Group = #{volunActAgeGroup}
AND SYSDATE BETWEEN VA.Volun_Act_Recru_Begin AND VA.Volun_Act_Recru_End
AND SYSDATE < VA.Volun_Act_Recru_Begin
AND SYSDATE > VA.Volun_Act_Recru_End
AND O.ORGAN_NAME LIKE CONCAT('%', #{organization}, '%')
AND VA.Volun_Act_Title LIKE CONCAT('%', #{keyword}, '%')
AND VA.Volun_Act_Point = #{keyword}
ORDER BY VA.Volun_Act_No DESC

SELECT COUNT(*)
FROM TBL_VOLUN_ACTIVITY



    Volun_Act_Recru_End >= SYSDATE



        AND Volun_Act_Act_Type = #{volunActActType}



        AND Volun_Act_Age_Group = #{volunActAgeGroup}



        AND Volun_Act_Recru_End >= SYSDATE




        AND Volun_Act_Recru_End < SYSDATE




        AND Volun_Act_Title LIKE CONCAT('%', #{keyword}, '%')



        AND Volun_Act_Point = #{keyword}
